/**
 * generate-bridge-types.mjs
 *
 * Reads the auto-generated `schema.ts` and produces `types.ts` with
 * convenience aliases for every schema component, plus the generic
 * ApiResponse / PagedResult wrappers.
 *
 * Run: node scripts/generate-bridge-types.mjs
 * (called automatically by `npm run generate-api`)
 */

import { readFileSync, writeFileSync } from 'fs';
import { resolve, dirname } from 'path';
import { fileURLToPath } from 'url';

const __dirname = dirname(fileURLToPath(import.meta.url));
const SCHEMA_PATH = resolve(__dirname, '../src/api/generated/schema.ts');
const OUTPUT_PATH = resolve(__dirname, '../src/api/generated/types.ts');

// ─── TypeScript reserved words (cannot be used as type aliases) ──
const TS_RESERVED = new Set([
  'break', 'case', 'catch', 'class', 'const', 'continue', 'debugger',
  'default', 'delete', 'do', 'else', 'enum', 'export', 'extends',
  'false', 'finally', 'for', 'function', 'if', 'import', 'in',
  'instanceof', 'new', 'null', 'return', 'super', 'switch', 'this',
  'throw', 'true', 'try', 'typeof', 'var', 'void', 'while', 'with',
  'as', 'implements', 'interface', 'let', 'package', 'private',
  'protected', 'public', 'static', 'yield', 'any', 'boolean',
  'constructor', 'declare', 'get', 'module', 'require', 'number',
  'set', 'string', 'symbol', 'type', 'from', 'of', 'namespace',
  'async', 'await', 'abstract', 'is', 'keyof', 'readonly', 'unique',
  'infer', 'never', 'unknown', 'asserts', 'bigint', 'override',
  // HTTP methods that might appear in paths block
  'post', 'put', 'patch', 'head', 'options', 'trace',
  'parameters', 'requestBody', 'responses',
]);

// ─── 1. Read schema.ts and extract schemas block ─────────────
const schemaContent = readFileSync(SCHEMA_PATH, 'utf-8');

// Find the `schemas: {` block inside `export interface components {`
// The components interface starts around line ~2696
const componentsMatch = schemaContent.match(
  /export\s+interface\s+components\s*\{[\s\S]*?schemas:\s*\{([\s\S]*?)\n {4}\};\s*\n/
);

if (!componentsMatch) {
  // Fallback: try to find schemas block with looser matching
  console.error('❌ Could not find schemas block inside "export interface components"');
  process.exit(1);
}

const schemasBlock = componentsMatch[1];

// Extract schema names at 8-space indent: "        SchemaName: {"
const schemaNameRegex = /^ {8}(\w+):\s*\{/gm;
const schemaNames = [];
const seen = new Set();
let match;

while ((match = schemaNameRegex.exec(schemasBlock)) !== null) {
  const name = match[1];
  // Skip reserved words and duplicates
  if (TS_RESERVED.has(name) || seen.has(name)) continue;
  // Must start with uppercase (schema types are PascalCase)
  if (!/^[A-Z]/.test(name)) continue;
  schemaNames.push(name);
  seen.add(name);
}

if (schemaNames.length === 0) {
  console.error('❌ No schema names found in schemas block');
  process.exit(1);
}

console.log(`📦 Found ${schemaNames.length} schemas in schema.ts`);

// ─── 2. Categorize schemas ──────────────────────────────────
const dtos = [];
const entities = [];
const pagedResults = [];
const enums = [];
const apiResponses = [];

for (const name of schemaNames) {
  if (name.endsWith('ApiResponse')) {
    apiResponses.push(name);
  } else if (name.endsWith('PagedResult')) {
    pagedResults.push(name);
  } else if (name.endsWith('Dto')) {
    dtos.push(name);
  } else if (name.endsWith('Status') || name.endsWith('Type') || name.endsWith('Resolution')) {
    enums.push(name);
  } else {
    entities.push(name);
  }
}

// ─── 3. Generate types.ts ───────────────────────────────────
const timestamp = new Date().toISOString().replace('T', ' ').slice(0, 19);

const lines = [
  `/**`,
  ` * Bridge Type Layer — OpenAPI Schema → Frontend Types`,
  ` *`,
  ` * ⚠️  AUTO-GENERATED by scripts/generate-bridge-types.mjs`,
  ` * ⚠️  DO NOT EDIT MANUALLY — run \`npm run generate-api\` instead.`,
  ` *`,
  ` * Generated: ${timestamp}`,
  ` * Schemas:   ${schemaNames.length} types exported`,
  ` *`,
  ` * This file re-exports convenience type aliases from the auto-generated schema.`,
  ` * It is the SINGLE SOURCE OF TRUTH for all API types used across the frontend.`,
  ` *`,
  ` * Usage:`,
  ` *   import type { SeriesDto, TasksDto, ApiResponse } from '../api/generated/types';`,
  ` *`,
  ` * DO NOT define manual DTO interfaces for entities that exist in the schema.`,
  ` * For frontend-only types (form state, UI state), keep them in feature/types/.`,
  ` */`,
  `import type { components } from './schema';`,
  ``,
];

const addSection = (title, names) => {
  if (names.length === 0) return;
  lines.push(`// ─── ${title} ${'─'.repeat(Math.max(0, 52 - title.length))}──`);
  for (const name of names) {
    lines.push(`export type ${name} = components["schemas"]["${name}"];`);
  }
  lines.push(``);
};

addSection('DTO Types (Read/Write)', dtos);
addSection('Entity Types (Raw DB Models)', entities);
addSection('Backend ApiResponse Wrappers', apiResponses);
addSection('Paged Result Wrappers', pagedResults);
addSection('Enum Types', enums);

// ─── 4. Add generic wrappers (hand-written, always appended) ─
lines.push(
  `// ─── Generic API Response ────────────────────────────────────`,
  `// Matches backend ApiResponse<T> with JsonNamingPolicy.CamelCase.`,
  `export interface ApiResponse<T> {`,
  `  success: boolean;`,
  `  statusCode: number;`,
  `  message: string;`,
  `  data: T;`,
  `  errors?: Record<string, string[] | null> | null;`,
  `}`,
  ``,
  `// ─── Generic Paged Result ────────────────────────────────────`,
  `export interface PagedResult<T> {`,
  `  items: T[] | null;`,
  `  pageNumber: number;`,
  `  pageSize: number;`,
  `  totalItems: number;`,
  `  totalPages: number;`,
  `  hasPreviousPage: boolean;`,
  `  hasNextPage: boolean;`,
  `}`,
  ``,
  `// ─── Convenience: Paged API Response ─────────────────────────`,
  `export type PagedApiResponse<T> = ApiResponse<PagedResult<T>>;`,
  ``,
);

// ─── 5. Write output ────────────────────────────────────────
writeFileSync(OUTPUT_PATH, lines.join('\n'), 'utf-8');
console.log(`✅ Generated types.ts with ${schemaNames.length} type aliases`);
console.log(`   DTOs: ${dtos.length} | Entities: ${entities.length} | ApiResponse: ${apiResponses.length} | Paged: ${pagedResults.length} | Enums: ${enums.length}`);
